mapper.select:
SELECT DISTINCT wwi.入库危废明细编号 as warehousingWasteItemId, wwi.入库单编号 as warehousingId, w.入库单号 as warehousingCode, w.入库时间 as warehousingTime, wwi.废物名称 as wasteName, wwi.废物代码 as wasteCode, wwi.危险特性 as hazardousFeatures, wwi.废物形态 as form, wwi.基本计量单位 as basicUnit, wwi.辅助计量单位 as auxiliaryUnit, wwi.是否启用辅助核算 as enableAuxiliaryAccounting, wwi.实际收运数量 as quantity, wwi.实际收运辅助数量 as auxiliaryQuantity, CASE WHEN pni.转移废物明细编号 IS NOT NULL THEN (SELECT CASE WHEN cwi.付款方 = '甲方' THEN '甲方' ELSE '乙方' END FROM CONTRACT_WASTE_ITEM cwi WHERE cwi.危废条目编号 = pni.危废条目编号 AND cwi.合同条目编号 IN ( SELECT 合同条目编号 FROM CONTRACT_ITEM WHERE 合同编号 = ( SELECT 合同号 FROM PICKUP_NOTICE WHERE 收运通知单号 = pni.收运通知单号 ) ) LIMIT 1) ELSE '乙方' END as payer, wwi.差异原因 as remark FROM WAREHOUSING_WASTE_ITEM wwi LEFT JOIN WAREHOUSING w ON wwi.入库单编号 = w.入库单编号 LEFT JOIN PICKUP_NOTICE_ITEM pni ON wwi.收运通知单明细编号 = pni.转移废物明细编号 WHERE w.入库单号 IN
#{code}
ORDER BY wwi.入库单编号, wwi.入库危废明细编号

SELECT DISTINCT w.入库单编号 as warehousingId, w.入库单号 as warehousingCode, w.入库时间 as warehousingTime, w.仓管员编码 as warehouseKeeperId, e.员工姓名 as warehouseKeeperName, w.入库备注 as remark, d.运输单号 as dispatchCode, pn.收运通知单号 as pickupNoticeCode, c.企业名称 as customerName, (SELECT SUM(wi.实际收运数量) FROM WAREHOUSING_WASTE_ITEM wi WHERE wi.入库单编号 = w.入库单编号) as totalWeight FROM WAREHOUSING w LEFT JOIN EMPLOYEE e ON w.仓管员编码 = e.员工编码 LEFT JOIN DISPATCH_ORDER d ON w.收运运输单号 = d.运输单号 LEFT JOIN PICKUP_NOTICE pn ON d.收运通知单号 = pn.收运通知单号 LEFT JOIN CUSTOMER c ON pn.客户编码 = c.客户编码 WHERE w.入库单号 IN
#{code}
ORDER BY w.入库时间 DESC
